const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;

const ITEM_BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

type Item = { type: string };
type QuoteStep = { op: "quote"; items: Item[] };
type Step = QuoteStep;
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const itemBase = (item: Item): number => ITEM_BASE_PREMIUM[item.type];

const quotePremium = (items: Item[]): number => {
  const policyBase = items.reduce((sum, item) => sum + itemBase(item), 0);
  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
  return Math.ceil(policyBase + firstInsurance) + PROCESSING_FEE;
};

export const runScenario = (scenario: Scenario): unknown => {
  const results = scenario.steps.map((step) => ({
    premium: quotePremium(step.items),
  }));
  return { results };
};

