  if (isComponent(type) && count === COMPONENT_BLOCK_SIZE) {
    return COMPONENT_BLOCK_PREMIUM;
  }
  return count * ITEM_BASE_PREMIUM[type];
};

const countByType = (items: Item[]): Map<string, number> => {
  const counts = new Map<string, number>();
  for (const item of items) {
    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
  }
  return counts;
};

const sumBasePremiums = (items: Item[]): number => {
  let total = 0;
  for (const [type, count] of countByType(items)) {
    total += groupedBasePremium(type, count);
