const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;

const ITEM_BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PREMIUM = 60;

type Item = { type: string };
type QuoteStep = { op: "quote"; items: Item[] };
type Step = QuoteStep;
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const isComponent = (type: string): boolean => COMPONENT_TYPES.has(type);

const groupedBasePremium = (type: string, count: number): number => {
  if (isComponent(type) && count === COMPONENT_BLOCK_SIZE) {
    return COMPONENT_BLOCK_PREMIUM;
  }
  return count * ITEM_BASE_PREMIUM[type];
};

const countByType = (items: Item[]): Map<string, number> => {
  const counts = new Map<string, number>();
  for (const item of items) {
    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
  }
  return counts;
};

const sumBasePremiums = (items: Item[]): number =>
  Array.from(countByType(items)).reduce(
    (total, [type, count]) => total + groupedBasePremium(type, count),
    0,
  );

const quotePremium = (items: Item[]): number => {
  const basePremium = sumBasePremiums(items);
  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
  const insurancePremium = Math.ceil(basePremium + firstInsuranceSurcharge);
  return insurancePremium + PROCESSING_FEE;
};

const runStep = (step: Step) => ({ premium: quotePremium(step.items) });

export const runScenario = (scenario: Scenario): unknown => ({
  results: scenario.steps.map(runStep),
});

