import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // ===== Premium: empty policy and base premiums =====
  it("empty item list → premium 5 G (only processing fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });
  it("single sword → 100 base + 10 first insurance + 5 fee = 115 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("single amulet → 60 base + 6 first insurance + 5 fee = 71 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("single staff → 80 base + 8 first insurance + 5 fee = 93 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "staff" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 93 }] });
  });
  it("single potion → 40 base + 4 first insurance + 5 fee = 49 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "potion" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 49 }] });
  });

  // ===== Components and block-of-3 discount =====
  it("single rune → 25 base + 2.5 first ins → ceil 28 + 5 fee = 33 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 33 }] });
  });
  it.todo("2 runes → 50 G base premium (no block) + 5 G fee = 55 G");
  it("3 runes → 60 G base (block) + 6 first ins + 5 fee = 71 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("4 runes → 100 base (no block) + 10 first ins + 5 fee = 115 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
          ],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("7 runes → 175 base + 17.5 first ins → ceil 193 + 5 fee = 198 G", () => {
    const runes = Array.from({ length: 7 }, () => ({ type: "rune" }));
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: runes }],
    });
    expect(result).toEqual({ results: [{ premium: 198 }] });
  });

  // ===== "Alike" components — same type only =====
  it("2 runes + 1 moonstone → 75 base (different types, no block) + 7.5 first ins → 83 + 5 fee = 88 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 88 }] });
  });
  it("3 runes + 3 moonstones → 120 base (two blocks) + 12 first ins + 5 fee = 137 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
            { type: "moonstone" },
            { type: "moonstone" },
            { type: "moonstone" },
          ],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 137 }] });
  });

  // ===== Item-specific modifiers =====
  it("cursed sword → 100 base + 50 curse + 10 first ins + 5 fee = 165 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", cursed: true }] }],
    });
    expect(result).toEqual({ results: [{ premium: 165 }] });
  });
  it("sword ench 5 → 100 base + 30 high-ench + 10 first ins + 5 fee = 145 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", enchantment: 5 }] }],
    });
    expect(result).toEqual({ results: [{ premium: 145 }] });
  });
  it.todo("sword with enchantment 4 has no high-enchantment surcharge → 100 + 5 = 105 G");
  it.todo("cursed sword with enchantment 5 → both surcharges (100 + 50 + 30 + 5 = 185 G)");

  // ===== Policy-wide modifiers =====
  it.todo("customer with exactly 2 years gets 20% loyalty discount → sword: 100 - 20 + 5 = 85 G");
  it.todo("first insurance adds 10% initial assessment surcharge → sword: 100 + 10 + 5 = 115 G");
  it.todo("follow-up contract (second quote) gets 15% discount → sword: 100 - 15 + 5 = 90 G");

  // ===== Modifier scope on multi-item policies =====
  it.todo("cursed sword + plain amulet → 160 base + 50 curse = 210 G + 5 fee = 215 G");

  // ===== Rounding =====
  it.todo("premium fractions rounded up (in MHPCO's favor) — e.g., 197.5 → 198 G");

  // ===== Integration examples =====
  it.todo("newcomer with cursed sword (0 yrs, first contract, ench 3) → 165 G");
  it.todo("long-standing customer's second contract cursed sword (3 yrs, ench 7) → 160 G");

  // ===== Quote error handling =====
  it.todo("quote with unknown item type → CLI exits non-zero with stderr message");

  // ===== Claims: standard reimbursement =====
  it.todo("regular sword (steel, ench 3), damage 500 G → payout 400 G (500 - 100 deductible)");
  it.todo("rune damage 200 G → payout 100 G (200 - 100 deductible)");

  // ===== Claims: special clauses =====
  it.todo("dragon-material sword full reimbursement: ench 5, damage 800 → payout 700");
  it.todo("high-enchantment (≥8) sword: steel ench 9, damage 1000 → payout 400 (50% then deductible)");
  it.todo("both clauses apply: dragon sword ench 9, damage 1000 → payout 400 (50% wins, then deductible)");
  it.todo("dragon sword exactly enchantment 8, damage 1000 → payout 400 (50% clause applies, then deductible)");

  // ===== Deductible per damage event =====
  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 (deductible per item)");

  // ===== Multiple items of same type =====
  it.todo("two swords, each damaged 500 by dragon → payout 800 (deductible applied to each)");
  it.todo("two sword damages but only one sword insured → CLI exits non-zero");

  // ===== Cap rules =====
  it.todo("sword + amulet insurance sum 1600, cap 3200 enforced");
  it.todo("cursed sword cap based on unmodified insurance value: cap 2000");
  it.todo("sword + 3 runes (block): insurance sum 1750 (block discount doesn't affect sum)");
  it.todo("two successive 1500 claims on sword (cap 2000): first payout 1400, then 600");

  // ===== Claim error handling =====
  it.todo("claim references item not in policy (amulet damage with only sword insured) → CLI exits non-zero");
  it.todo("claim with negative damage amount → CLI exits non-zero");

  // ===== Payout rounding =====
  it.todo("payout fractions rounded down (in MHPCO's favor) — e.g., 350.5 → 350 G");
});

