const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;
const CURSE_SURCHARGE_RATE = 0.5;
const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;

const COMPONENT_BASE_PREMIUM = 25;
const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PREMIUM = 60;

const NON_COMPONENT_BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const isComponent = (type: string): boolean => COMPONENT_TYPES.has(type);

const basePremiumFor = (type: string): number =>
  isComponent(type) ? COMPONENT_BASE_PREMIUM : NON_COMPONENT_BASE_PREMIUM[type];

type Item = { type: string; cursed?: boolean; enchantment?: number };
type QuoteStep = { op: "quote"; items: Item[] };
type Step = QuoteStep;
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const groupedBasePremium = (type: string, count: number): number => {
  if (isComponent(type) && count === COMPONENT_BLOCK_SIZE) {
    return COMPONENT_BLOCK_PREMIUM;
  }
  return count * basePremiumFor(type);
};

const countByType = (items: Item[]): Map<string, number> => {
  const counts = new Map<string, number>();
  for (const item of items) {
    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
  }
  return counts;
};

const sumBasePremiums = (items: Item[]): number =>
  Array.from(countByType(items)).reduce(
    (total, [type, count]) => total + groupedBasePremium(type, count),
    0,
  );

const surchargeFor = (item: Item, applies: boolean, rate: number): number =>
  applies ? basePremiumFor(item.type) * rate : 0;

const isCursed = (item: Item): boolean => item.cursed === true;

const isHighlyEnchanted = (item: Item): boolean =>
  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;

const itemSurchargeFor = (item: Item): number =>
  surchargeFor(item, isCursed(item), CURSE_SURCHARGE_RATE) +
  surchargeFor(item, isHighlyEnchanted(item), HIGH_ENCHANTMENT_SURCHARGE_RATE);

const sumItemSurcharges = (items: Item[]): number =>
  items.reduce((sum, item) => sum + itemSurchargeFor(item), 0);

const quotePremium = (items: Item[]): number => {
  const basePremium = sumBasePremiums(items);
  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
  const insurancePremium = Math.ceil(
    basePremium + sumItemSurcharges(items) + firstInsuranceSurcharge,
  );
  return insurancePremium + PROCESSING_FEE;
};

const runStep = (step: Step) => ({ premium: quotePremium(step.items) });

export const runScenario = (scenario: Scenario): unknown => ({
  results: scenario.steps.map(runStep),
});

